using System; using System.Drawing; using System.Windows.Forms; using System.Data; namespace CalculatorApp { public partial class Form1 : Form { private TextBox display; private TableLayoutPanel table; public Form1() { InitializeComponent(); if (System.IO.File.Exists("app.ico")) this.Icon = new Icon("app.ico"); } private void InitializeComponent() { this.Text = "Calculadora Simples"; this.Size = new Size(320, 450); this.MinimumSize = new Size(300, 400); display = new TextBox { Dock = DockStyle.Top, Font = new Font("Segoe UI", 24), TextAlign = HorizontalAlignment.Right, ReadOnly = true, Height = 50 }; table = new TableLayoutPanel { Dock = DockStyle.Fill, ColumnCount = 4, RowCount = 5 }; table.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 25f)); table.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 25f)); table.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 25f)); table.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 25f)); string[] buttons = { "C", "", "DEL", "/", "7", "8", "9", "*", "4", "5", "6", "-", "1", "2", "3", "+", "0", ".", "=", "" }; foreach (var text in buttons) { if (string.IsNullOrEmpty(text)) continue; Button btn = new Button { Text = text, Dock = DockStyle.Fill, Font = new Font("Segoe UI", 14), FlatStyle = FlatStyle.Flat }; btn.Click += Button_Click; table.Controls.Add(btn); } this.Controls.Add(table); this.Controls.Add(display); } private void Button_Click(object sender, EventArgs e) { string text = ((Button)sender).Text; if (text == "C") display.Text = ""; else if (text == "DEL") { if (display.Text.Length > 0) display.Text = display.Text.Substring(0, display.Text.Length - 1); } else if (text == "=") { try { DataTable dt = new DataTable(); var result = dt.Compute(display.Text, ""); display.Text = result.ToString(); } catch { display.Text = "Erro"; } } else { display.Text += text; } } } }